import React from 'react';
import { Link } from 'react-router-dom';
import styles from '../pages/PageStyle2.module.css';
import layout2 from '../styles/layout2.module.css';

function EmployeeLayout({ children, title }) {
  const handleLogout = () => {
    localStorage.removeItem('userInfo');
    window.location.href = '/login';
  };

  return (
    <div className={styles.pageContainer}>
      <div className={styles.leftPanel}>
        <img src="/logo.png" alt="Comic Collective Logo" className={styles.logo} />
        <nav className={styles.menuNav}>
          <Link to="/dashempl" className={styles.menuItem}>Dashboard</Link>
          <Link to="/inventory" className={styles.menuItem}>Inventory</Link>
          <Link to="/cust" className={styles.menuItem}>Customers</Link>
          <Link to="/empl" className={styles.menuItem}>Employees</Link>
        </nav>
        <div className={styles.bottomNav}>
          <Link to="/settings" className={styles.menuItem}>Settings</Link>
          <button onClick={handleLogout} className={styles.logoutButton}>Log out</button>
        </div>
      </div>
      <div className={styles.rightPanel}>
        {title && (
          <>
            <h1 className={styles.pageHeader}>{title}</h1>
            <hr className={styles.hr} />
          </>
        )}
        <div className={styles.mainContent}>
          {children}
        </div>
      </div>
    </div>
  );
}

export default EmployeeLayout;
